package fizeau

import (
	"context"
	"fmt"
	"io"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/routehealth"
	"github.com/easel/fizeau/internal/serviceimpl"
	sessionusage "github.com/easel/fizeau/internal/session"
)

// FizeauService is the entire public Go surface of the fizeau module.
// See CONTRACT-003 for the full specification.
type FizeauService interface {
	Execute(ctx context.Context, req ServiceExecuteRequest) (<-chan ServiceEvent, error)
	TailSessionLog(ctx context.Context, sessionID string) (<-chan ServiceEvent, error)
	ListHarnesses(ctx context.Context) ([]HarnessInfo, error)
	ListProviders(ctx context.Context) ([]ProviderInfo, error)
	ListModels(ctx context.Context, filter ModelFilter) ([]ModelInfo, error)
	ListPolicies(ctx context.Context) ([]PolicyInfo, error)
	HealthCheck(ctx context.Context, health HealthTarget) error
	ResolveRoute(ctx context.Context, req RouteRequest) (*RouteDecision, error)
	RecordRouteAttempt(ctx context.Context, attempt RouteAttempt) error
	RouteStatus(ctx context.Context) (*RouteStatusReport, error)

	// Historical session-log projections. CONTRACT-003 owns these so CLI
	// subcommands such as log/replay/usage do not need to read the
	// internal session-log JSONL schema.
	UsageReport(ctx context.Context, opts UsageReportOptions) (*UsageReport, error)
	ListSessionLogs(ctx context.Context) ([]SessionLogEntry, error)
	WriteSessionLog(ctx context.Context, sessionID string, w io.Writer) error
	ReplaySession(ctx context.Context, sessionID string, w io.Writer) error
}

// ServiceConfig provides provider and routing data to the service without
// creating an import cycle from the root package into agent/config.
// Callers wrap their loaded *config.Config in a type that satisfies this interface.
type ServiceConfig interface {
	// ProviderNames returns provider names in stable order (default first).
	ProviderNames() []string
	// DefaultProviderName returns the name of the configured default provider.
	DefaultProviderName() string
	// Provider returns the raw config values for a named provider.
	Provider(name string) (ServiceProviderEntry, bool)
	// HealthCooldown returns the configured cooldown duration (0 = use default 30s).
	HealthCooldown() time.Duration
	// WorkDir is the base directory for file-backed health state.
	WorkDir() string
	// SessionLogDir returns the configured sessions directory.
	SessionLogDir() string
}

// ServiceProviderEntry carries the minimal provider data the service needs.
type ServiceProviderEntry struct {
	Type           string // "openai" | "openrouter" | "lmstudio" | "llama-server" | "ds4" | "omlx" | "lucebox" | "vllm" | "rapid-mlx" | "ollama" | "anthropic"
	BaseURL        string
	ServerInstance string
	Endpoints      []ServiceProviderEndpoint
	APIKey         string
	Headers        map[string]string
	Model          string // configured default model (may be empty)
	Billing        BillingModel
	// IncludeByDefault reports whether this provider participates in automatic
	// routing when the caller does not pin a provider.
	IncludeByDefault    bool
	IncludeByDefaultSet bool
	// ContextWindow is the configured provider-side context override.
	ContextWindow int
	// ConfigError marks this provider entry invalid while allowing the rest of
	// the service config to load. Invalid providers are reported in status
	// surfaces and excluded from routing.
	ConfigError string
	// DailyTokenBudget is the operator-configured per-UTC-day token budget
	// (request + response) for this provider. Zero means no local burn-rate
	// prediction; the provider's own quota signal still applies.
	DailyTokenBudget int
}

// ServiceProviderEndpoint is one configured provider serving endpoint.
type ServiceProviderEndpoint struct {
	Name           string
	BaseURL        string
	ServerInstance string
}

// ServiceOptions configures a FizeauService instance.
//
// seamOptions is embedded so production builds (no testseam tag) get an
// empty struct — making it a compile-time error to set seam fields without
// the build tag. Test builds inherit the four CONTRACT-003 seams
// (FakeProvider, PromptAssertionHook, CompactionAssertionHook,
// ToolWiringHook) automatically.
type ServiceOptions struct {
	seamOptions

	ConfigPath string    // optional override; default $XDG_CONFIG_HOME/fizeau/config.yaml
	Logger     io.Writer // optional; agent writes structured session logs internally regardless

	// ServiceConfig, when non-nil, supplies provider and routing data for
	// ListProviders and HealthCheck. Pass a value wrapping the loaded config.
	// When nil, those methods return an error.
	ServiceConfig ServiceConfig

	// QuotaRefreshDebounce is the minimum interval between live quota probes for
	// a primary subscription harness. Zero uses the service default.
	QuotaRefreshDebounce time.Duration
	// QuotaRefreshStartupWait bounds startup waiting when the durable quota
	// cache is missing, stale, or incomplete. Zero uses the service default.
	QuotaRefreshStartupWait time.Duration
	// QuotaRefreshInterval enables periodic refresh for long-running server
	// processes. Zero disables the timer; cache refresh still happens on startup
	// and service activity.
	QuotaRefreshInterval time.Duration
	// QuotaRefreshContext optionally cancels the periodic server refresh worker.
	// When nil, the worker uses context.Background().
	QuotaRefreshContext context.Context

	// CatalogProbeTimeout bounds live /v1/models discovery during routing.
	// Zero uses the service default of 2s.
	CatalogProbeTimeout time.Duration
	// CatalogReloadTimeout bounds stale-while-revalidate catalog reloads.
	// Zero uses the service default of 30s.
	CatalogReloadTimeout time.Duration

	// LocalCostUSDPer1kTokens is the operator-supplied electricity/operations
	// estimate for local endpoint providers under the embedded agent harness.
	// Zero means local endpoint cost is unknown.
	LocalCostUSDPer1kTokens float64
	// SubscriptionCostCurve optionally overrides the default subscription
	// effective-cost curve used by routing.
	SubscriptionCostCurve *SubscriptionCostCurve

	// SessionLogDir overrides the directory used by historical session-log
	// projections (UsageReport, ListSessionLogs, WriteSessionLog,
	// ReplaySession). Empty falls back to ServiceConfig.SessionLogDir().
	// Per-Execute requests still set their own
	// ServiceExecuteRequest.SessionLogDir.
	SessionLogDir string

	// StaleHarnessReaperGrace is the minimum age before a startup reaper may
	// terminate an owned subprocess record. Zero uses the default grace window.
	StaleHarnessReaperGrace time.Duration

	// HealthProbeInterval is the interval between background aliveness probes
	// for configured non-cloud providers. Zero uses the default (60s).
	HealthProbeInterval time.Duration
	// HealthSignalTTL is the maximum age of a probe result before it expires
	// for routing purposes. Zero uses the default (10 min).
	HealthSignalTTL time.Duration
	// PersistRouteHealth, when non-empty, is the file path where probe results
	// are persisted across processes so a fresh process skips redundant probing.
	PersistRouteHealth string
	// AlivenessProber, when non-nil, overrides the default TCP-connect prober
	// used during startup and periodic aliveness probing. Nil uses the default.
	AlivenessProber ProviderAlivenessProber
}

// SubscriptionCostCurve tunes effective subscription cost by quota utilization.
// Thresholds are percentages used, and multipliers are applied to the
// equivalent pay-per-token catalog rate.
type SubscriptionCostCurve struct {
	FreeUntilPercent   int
	LowUntilPercent    int
	MediumUntilPercent int
	LowMultiplier      float64
	MediumMultiplier   float64
	HighMultiplier     float64
}

// QuotaState is a live quota snapshot for a harness. Nil means not applicable.
type QuotaState struct {
	Windows    []harnesses.QuotaWindow `json:"windows"`
	CapturedAt time.Time               `json:"captured_at"`
	Fresh      bool                    `json:"fresh"`
	Source     string                  `json:"source,omitempty"`
	Status     string                  `json:"status,omitempty"` // ok|stale|unavailable|unauthenticated|unknown
	LastError  *StatusError            `json:"last_error,omitempty"`
}

// StatusError describes the most recent normalized status error for a harness,
// provider, or endpoint.
type StatusError struct {
	Type      string    // unavailable|unauthenticated|error
	Detail    string    // human-readable detail, safe for diagnostics
	Source    string    // config path, endpoint, cache path, or probe name
	Timestamp time.Time // zero when the source did not include a timestamp
}

// AccountStatus describes authentication/account state without exposing
// provider-specific native files to consumers.
type AccountStatus struct {
	Authenticated   bool
	Unauthenticated bool
	Email           string
	PlanType        string
	OrgName         string
	Source          string
	CapturedAt      time.Time
	Fresh           bool
	Detail          string
}

// UsageWindow describes normalized usage attribution over a time window.
// Empty token/cost totals mean the service has no historical usage source yet.
type UsageWindow struct {
	Name                string
	Source              string
	CapturedAt          time.Time
	Fresh               bool
	InputTokens         int
	OutputTokens        int
	TotalTokens         int
	CacheReadTokens     int
	CacheWriteTokens    int

package fizeau

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"strings"
	"sync/atomic"
	"time"

	"github.com/easel/fizeau/internal/compaction"
	agentcore "github.com/easel/fizeau/internal/core"
	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/modelcatalog"
	"github.com/easel/fizeau/internal/reasoning"
	"github.com/easel/fizeau/internal/routing"
	"github.com/easel/fizeau/internal/serviceimpl"
	"github.com/easel/fizeau/internal/tool"
)

// generateSessionID returns a unique session identifier for a new Execute.
func generateSessionID() string {
	return fmt.Sprintf("svc-%d", time.Now().UnixNano())
}

// Execute runs an agent task in-process; emits Events on the returned
// channel until the task terminates (channel closes). The final event
// (type=final) carries status, usage, cost, session-log path, and the
// resolved fallback chain that fired.
//
// See CONTRACT-003 §"Behaviors the contract guarantees" for the full
// behavior contract this method honors:
//   - Orphan-model validation (Status=failed when Model unknown)
//   - Provider-deadline wrapping (Timeout + IdleTimeout + ProviderTimeout)
//   - StallPolicy enforcement (stall event before final)
//   - Route-reason attribution (routing_decision start, routing_actual final)
//   - OS-level subprocess cleanup on ctx.Done()
//   - Metadata bidirectional echo (events + session log)
//   - SessionLogDir per-request override
//
// Routing: under-specified requests (no Harness) are dispatched through
// internal/routing.Resolve via ResolveRoute. Callers can run with bare
// Policy/Model/Provider — the engine picks. NativeProvider must
// still be supplied for the native path until provider construction lands
// in a follow-up.
func (s *service) Execute(ctx context.Context, req ServiceExecuteRequest) (<-chan ServiceEvent, error) {
	// Boundary validation: reject unknown CachePolicy values before any
	// session state is opened or events are emitted. Beads C/D consume this
	// field; an unknown value is a caller programming error.
	if err := ValidateCachePolicy(req.CachePolicy); err != nil {
		return nil, err
	}
	if err := ValidatePowerBounds(req.MinPower, req.MaxPower); err != nil {
		return nil, err
	}
	if err := ValidateRole(req.Role); err != nil {
		return nil, err
	}
	if err := ValidateCorrelationID(req.CorrelationID); err != nil {
		return nil, err
	}

	// Generate a session ID and register it in the hub so TailSessionLog
	// callers can subscribe before or during execution.
	sessionID := generateSessionID()
	fanout := s.executeEventFanout()
	fanout.openSession(sessionID)

	outer := make(chan ServiceEvent, 64)

	// ADR-006 §3/§4: capture the override context (user pin + unconstrained
	// auto decision) before route resolution so we can fire the matching
	// override / rejected_override event regardless of which path the route
	// resolution takes.
	overrideCtx := s.buildOverrideContext(ctx, req)

	// ADR-006 §5: record this request into the routing-quality store so
	// auto_acceptance_rate / override_disagreement_rate / class_breakdown
	// reflect both overridden and non-overridden traffic. The recorded
	// override payload carries no outcome — outcome aggregation for live
	// requests is best-effort and lives in session logs once that
	// persistence path lands.
	s.recordRoutingQualityForRequest(overrideCtx)

	// Resolve the route.
	decision, err := s.executeRouteResolver().resolveExecuteRoute(req)
	if err != nil {
		// NoViableProviderForNow is a transient quota signal — DDx
		// callers pause their drain loop on RetryAfter and resume.
		// Surface it directly (not via the fatal-final channel) so the
		// typed error reaches errors.As without log scraping.
		var quotaErr *NoViableProviderForNow
		if errors.As(err, &quotaErr) {
			fanout.closeSession(sessionID, ServiceEvent{})
			return nil, err
		}
		if isExplicitPinError(err) {
			// Emit a rejected_override event (no outcome) when the pin
			// fails pre-dispatch. Surface the typed error wrapped with
			// the rejected_override payload so callers that errors.As
			// the typed pin error still get it; callers wanting the
			// telemetry can extract via AsRejectedOverride.
			pinErr := err
			if overrideCtx != nil {
				if rejectedEv, payload, ok := makeRejectedOverrideEvent(overrideCtx, sessionID, pinErr, req.Metadata); ok {
					fanout.broadcastEvent(sessionID, rejectedEv)
					// Persist the rejected_override to the session log so
					// UsageReport's windowed scan (which sources from
					// session logs, not the in-memory ring) sees this
					// rejection. The pin failed pre-dispatch, so no
					// runExecute will open a log for this session — open
					// one briefly here, write session.start + the rejected
					// payload, and close.
					s.persistRejectedOverride(req, sessionID, payload)
					pinErr = &ErrRejectedOverride{Inner: err, Event: payload}
				}
			}
			fanout.closeSession(sessionID, ServiceEvent{})
			return nil, pinErr
		}
		// Still return a channel that yields a single failed final event so
		// downstream consumers don't have to special-case the error path.
		// Also close the hub session so TailSessionLog subscribers unblock.
		go func() {
			emitFatalFinal(outer, req.Metadata, "failed", err.Error())
			// Drain outer to get the final event and forward to hub.
			// emitFatalFinal closes outer; read the single event from it.
		}()
		// We can't easily intercept emitFatalFinal here, so close the hub
		// session with an empty final immediately — callers on TailSessionLog
		// for a failed-route session get an empty close.
		go func() {
			// Wait briefly for emitFatalFinal to write.
			time.Sleep(10 * time.Millisecond)
			fanout.closeSession(sessionID, ServiceEvent{})
		}()
		return outer, nil
	}

	// Metadata seam: every event we emit echoes req.Metadata.
	meta := req.Metadata

	// Wrap the inner channel through the hub so every event is broadcast to
	// TailSessionLog subscribers. The fan-out goroutine owns outer's close
	// and is responsible for inserting the override event (if any) immediately
	// before the final event per ADR-006 §7.
	inner := fanout.wrapExecuteWithHub(sessionID, outer, overrideCtx, meta)

	// Emit start-of-execution routing_decision so consumers know the picked
	// chain before any real work fires. The actual chain (post-fallback) is
	// stamped onto the final event's RoutingActual field.
	go s.runExecute(ctx, req, *decision, meta, inner, sessionID, overrideCtx)
	return outer, nil
}

// resolveExecuteRoute reduces the request to a concrete RouteDecision.
// The request is dispatched through the routing engine
// (internal/routing.Resolve) when under-specified (Harness == ""), or when
// Harness is set but Model is empty and routing inputs (Policy or MinPower)
// are present (engine runs within the harness's eligible models). When Harness
// is set and Model is also set, the decision is accepted verbatim.
func (s *service) resolveExecuteRoute(req ServiceExecuteRequest) (*RouteDecision, error) {
	// If Harness is omitted, route through the engine. The engine defaults to
	// local-first and auto-selects from configured endpoints when no other
	// constraints are specified — an empty request is valid if providers exist.
	if req.Harness == "" {
		return s.resolveExecuteRouteWithEngine(req)
	}
	canonical := harnesses.ResolveHarnessAlias(req.Harness)
	if !s.registry.Has(canonical) {
		return nil, fmt.Errorf("unknown harness %q", req.Harness)
	}
	cfg, _ := s.registry.Get(canonical)

	// Run per-field validators first so callers get the most specific error.
	// Empty-model routing checks run after these, right before model resolution.
	if err := validateExplicitHarnessPolicy(canonical, cfg, req.Policy); err != nil {
		return nil, err
	}
	if err := validateExplicitProvider(s.opts.ServiceConfig, cfg, req.Provider); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessModel(canonical, cfg, req.Model, req.Provider); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessReasoning(canonical, cfg, req.Reasoning); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessQuota(canonical, cfg); err != nil {
		return nil, err
	}

	// Empty-model routing: only applies to subprocess harnesses with concrete
	// model semantics. TestOnly (virtual/script), HTTP-provider (openrouter/
	// lmstudio/etc.), and "fiz" harnesses skip this block — they either use
	// DefaultModel directly or have provider-side model semantics.
	if !cfg.TestOnly && !cfg.IsHTTPProvider && canonical != "fiz" && req.Model == "" {
		if req.Policy == "" && req.MinPower == 0 {
			// Under-specified: no model, no routing inputs → silent empty model
			// avoided by failing early with a clear diagnostic.
			return nil, fmt.Errorf("under-specified routing for harness=%q: "+
				"supply --model, --policy, or --min-power", canonical)
		}
		// Policy or MinPower present: run the routing engine within the
		// harness's eligible models. Class 2 harnesses (AutoRoutingEligible=false:
		// gemini, opencode, pi) require an explicit --model.
		if !cfg.AutoRoutingEligible {
			return nil, fmt.Errorf("no auto-resolution available for harness=%q: "+
				"harness does not support auto-routing; supply an explicit --model", canonical)
		}
		return s.resolveExecuteRouteWithEngine(req)
	}

	resolvedModel := resolveSubprocessModelAlias(canonical, req.Model)
	decision := &RouteDecision{
		Harness:  canonical,
		Provider: req.Provider,
		Model:    resolvedModel,
		Reason:   "explicit",
		Power:    catalogPowerForModel(serviceRoutingCatalog(), resolvedModel),
	}
	if decision.Endpoint == "" {
		_, endpoint, _ := splitEndpointProviderRef(decision.Provider)
		decision.Endpoint = endpoint
	}
	return decision, nil
}

func validateExplicitHarnessQuota(name string, cfg harnesses.HarnessConfig) error {
	if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelSubscription {
		return nil
	}
	now := time.Now()
	qs, ok := subscriptionQuotaForHarness(name, now)
	if !ok || !qs.Present || !qs.Fresh || qs.OK {
		return nil
	}
	return explicitQuotaUnavailable(name, qs.Windows, now)
}

package fizeau

import (
	"context"
	"sync/atomic"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/serviceimpl"
)

type executeRouteResolver interface {
	resolveExecuteRoute(ServiceExecuteRequest) (*RouteDecision, error)
}

type executeSessionLogOpener interface {
	openSessionLog(ServiceExecuteRequest, RouteDecision, string) *serviceSessionLog
}

type executeEventFanout interface {
	openSession(string)
	broadcastEvent(string, ServiceEvent)
	closeSession(string, ServiceEvent)
	wrapExecuteWithHub(string, chan ServiceEvent, *overrideContext, map[string]string) chan ServiceEvent
}

type executeRunnerInvoker interface {
	dispatchExecuteRun(context.Context, executeRunContext)
}

type executeRunContext struct {
	req      ServiceExecuteRequest
	decision RouteDecision
	meta     map[string]string
	out      chan<- ServiceEvent
	seq      *atomic.Int64
	start    time.Time
	sl       *serviceSessionLog
	session  string
}

func (s *service) executeRouteResolver() executeRouteResolver {
	return s
}

func (s *service) executeSessionLogOpener() executeSessionLogOpener {
	return s
}

func (s *service) executeEventFanout() executeEventFanout {
	return s.hub
}

func (s *service) executeRunnerInvoker() executeRunnerInvoker {
	return s
}

func (s *service) dispatchExecuteRun(ctx context.Context, run executeRunContext) {
	decision := serviceimpl.ExecuteRunnerDecision{
		Harness:  run.decision.Harness,
		Provider: run.decision.Provider,
		Model:    run.decision.Model,
	}
	serviceimpl.DispatchExecuteRun(ctx, serviceimpl.ExecuteDispatchRequest{
		Decision: decision,
		Started:  run.start,
	}, serviceimpl.ExecuteDispatchCallbacks{
		RunNative: func(ctx context.Context) {
			s.runNative(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
		},
		RunSubprocess: func(ctx context.Context, runner harnesses.Harness) {
			s.runSubprocess(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session, runner)
		},
		RunVirtual: func(ctx context.Context) {
			s.runVirtual(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
		},
		RunScript: func(ctx context.Context) {
			s.runScript(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
		},
		IsHTTPProvider: func(harness string) bool {
			cfg, ok := s.registry.Get(harness)
			return ok && cfg.IsHTTPProvider
		},
		Finalize: func(final harnesses.FinalData) {
			finalizeAndEmit(run.out, run.seq, run.meta, run.req, run.sl, final)
		},
	})
}

package serviceimpl

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"strings"
	"sync/atomic"
	"time"

	agentcore "github.com/easel/fizeau/internal/core"
	"github.com/easel/fizeau/internal/harnesses"
)

const (
	defaultStallReadOnlyIterations = 25
	defaultMaxIterations           = 200
)

var nativeReadOnlyTools = map[string]bool{
	"read":       true,
	"read_file":  true,
	"grep":       true,
	"ls":         true,
	"find":       true,
	"cat":        true,
	"head":       true,
	"tail":       true,
	"stat":       true,
	"web_fetch":  true,
	"web_search": true,
}

// NativeDecision is the API-neutral routing data needed by the native runner.
type NativeDecision struct {
	Harness        string
	Provider       string
	ServerInstance string
	Model          string
	Candidates     []NativeRouteCandidate
}

// NativeRouteCandidate is the API-neutral subset of root RouteCandidate used
// by the native failover provider.
type NativeRouteCandidate struct {
	Provider       string
	Endpoint       string
	ServerInstance string
	Model          string
	Eligible       bool
}

// NativeRequest is the API-neutral request data needed by the native runner.
type NativeRequest struct {
	Prompt                    string
	SystemPrompt              string
	Model                     string
	Provider                  string
	Harness                   string
	WorkDir                   string
	Temperature               *float32
	TopP                      *float64
	TopK                      *int
	MinP                      *float64
	RepetitionPenalty         *float64
	Seed                      *int64
	SamplingSource            string
	Reasoning                 agentcore.Reasoning
	NoStream                  bool
	Permissions               string
	Tools                     []agentcore.Tool
	ToolPreset                string
	PlanningMode              bool
	MaxIterations             int
	MaxTokens                 int
	ReasoningByteLimit        int
	ProviderTimeout           time.Duration
	Timeout                   time.Duration
	CachePolicy               string
	StallMaxReadOnlyIteration *int
	Metadata                  map[string]string
	Decision                  NativeDecision
	Started                   time.Time
	SessionID                 string
	// CostCapUSD mirrors ServiceExecuteRequest.CostCapUSD. See
	// internal/core.Request.CostCapUSD for the enforcement contract.
	CostCapUSD float64
}

// NativeProviderRequest is the narrow provider-selection request that crosses
// from the internal runner back into root-owned provider configuration.
type NativeProviderRequest struct {
	Provider string
	Harness  string
	Model    string
}

// NativeProviderResolution is the API-neutral result of root-owned provider
// construction.
type NativeProviderResolution struct {
	Provider agentcore.Provider
	Name     string
	Model    string
}

// NativeCallbacks are root-owned service seams used by the internal runner
// without importing root public contract types.
type NativeCallbacks struct {
	ResolveProvider            func(NativeProviderRequest) NativeProviderResolution
	ProviderNotConfiguredError func(NativeProviderRequest, NativeDecision) string
	Compactor                  func(model string) agentcore.Compactor
	ObserveAgentEvent          func(agentcore.Event)
	EmitEvent                  func(harnesses.EventType, any)
	BeforeFinal                func(harnesses.FinalData)
	Finalize                   func(harnesses.FinalData)
	ToolWiringHook             func(harness string, toolNames []string)
	PromptAssertionHook        func(systemPrompt, prompt string, contextFiles []string)
	CompactionAssertionHook    func(messagesBefore, messagesAfter, tokensFreed int)
	ObserveTokenUsage          func(provider string, tokens int, at time.Time)
}

// RunNative drives the in-process agent loop without depending on root public
// service types.
func RunNative(ctx context.Context, req NativeRequest, cb NativeCallbacks) {
	provider := nativeExecutionProvider(req, cb.ResolveProvider)
	actualHarness := req.Decision.Harness
	if actualHarness == "" {
		actualHarness = "fiz"
	}
	resolvedProvider := resolveProvider(cb.ResolveProvider, nativeProviderRequest(req, req.Decision))
	actualProvider := resolvedProvider.Name
	if actualProvider == "" {
		actualProvider = req.Decision.Provider
	}
	actualModel := req.Decision.Model
	if actualModel == "" {
		actualModel = resolvedProvider.Model
	}
	if provider == nil {
		finalize(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      providerNotConfiguredError(cb.ProviderNotConfiguredError, req, req.Decision),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        actualHarness,
				Provider:       actualProvider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          actualModel,
			},
		})
		return
	}
	permission, permissionErr := nativePermissionMode(req.Permissions)
	if permissionErr != nil {
		finalize(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      permissionErr.Error(),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        actualHarness,
				Provider:       actualProvider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          actualModel,
			},
		})
		return
	}

	if req.ProviderTimeout > 0 {
		provider = wrapProviderRequestTimeout(provider, req.ProviderTimeout)
	}

	policyMax := defaultStallReadOnlyIterations
	if req.StallMaxReadOnlyIteration != nil {
		policyMax = *req.StallMaxReadOnlyIteration
	}
	maxIter := req.MaxIterations
	if maxIter <= 0 {
		maxIter = defaultMaxIterations
	}

	var (
		readOnlyStreak atomic.Int64
		stalled        atomic.Bool
		stallReason    atomic.Value
		stallCount     atomic.Int64
	)
	cancelCtx, cancel := context.WithCancel(ctx)
	defer cancel()

	loopCB := func(ev agentcore.Event) {
		if cb.ObserveAgentEvent != nil {
			cb.ObserveAgentEvent(ev)
		}
		switch ev.Type {
		case agentcore.EventToolCall:
			var payload nativeToolCallPayload
			_ = json.Unmarshal(ev.Data, &payload)
			if !toolLikelyMakesProgress(payload.Tool, payload) {
				if v := readOnlyStreak.Add(1); policyMax > 0 && int(v) >= policyMax {
					if stalled.CompareAndSwap(false, true) {
						stallReason.Store("no_progress_tools_exceeded")
						stallCount.Store(v)
						cancel()
					}
				}
			} else {
				readOnlyStreak.Store(0)
			}
		case agentcore.EventCompactionEnd:
			if cb.CompactionAssertionHook != nil {
				var payload nativeCompactionPayload
				_ = json.Unmarshal(ev.Data, &payload)
				cb.CompactionAssertionHook(payload.MessagesBefore, payload.MessagesAfter, payload.TokensBefore-payload.TokensAfter)
			}
		}
	}

	tools := filterNativeToolsForPermission(req.Tools, permission)
	if cb.ToolWiringHook != nil {
		cb.ToolWiringHook(req.Decision.Harness, ToolNames(tools))
	}
	if cb.PromptAssertionHook != nil {
		cb.PromptAssertionHook(req.SystemPrompt, req.Prompt, nil)
	}

	var compactor agentcore.Compactor
	if cb.Compactor != nil {
		compactor = cb.Compactor(actualModel)
	}
	var temperature *float64
	if req.Temperature != nil {
		t := float64(*req.Temperature)
		temperature = &t
	}
	var seed int64
	if req.Seed != nil {
		seed = *req.Seed
	}
	loopReq := agentcore.Request{
		Prompt:             req.Prompt,
		SystemPrompt:       req.SystemPrompt,
		Provider:           provider,
		Tools:              tools,
		WorkDir:            req.WorkDir,
		Callback:           loopCB,
		Metadata:           req.Metadata,
		MaxIterations:      maxIter,
		ResolvedModel:      actualModel,
		SelectedProvider:   actualProvider,
		Temperature:        temperature,
		TopP:               req.TopP,
		TopK:               req.TopK,
		MinP:               req.MinP,
		RepetitionPenalty:  req.RepetitionPenalty,
		Seed:               seed,
		SamplingSource:     req.SamplingSource,
		Reasoning:          req.Reasoning,
		NoStream:           req.NoStream,

package serviceimpl

import (
	"context"
	"fmt"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	claudeharness "github.com/easel/fizeau/internal/harnesses/claude"
	codexharness "github.com/easel/fizeau/internal/harnesses/codex"
	geminiharness "github.com/easel/fizeau/internal/harnesses/gemini"
	opencodeharness "github.com/easel/fizeau/internal/harnesses/opencode"
	piharness "github.com/easel/fizeau/internal/harnesses/pi"
)

// ExecuteDispatchRequest carries API-neutral data needed to choose the
// concrete execute runner.
type ExecuteDispatchRequest struct {
	Decision ExecuteRunnerDecision
	Started  time.Time
}

// ExecuteDispatchCallbacks connect the internal dispatcher to root-owned
// public event/session adapters.
type ExecuteDispatchCallbacks struct {
	RunNative      func(context.Context)
	RunSubprocess  func(context.Context, harnesses.Harness)
	RunVirtual     func(context.Context)
	RunScript      func(context.Context)
	IsHTTPProvider func(harness string) bool
	Finalize       func(harnesses.FinalData)
}

// DispatchExecuteRun selects the concrete runner for an Execute request.
func DispatchExecuteRun(ctx context.Context, req ExecuteDispatchRequest, cb ExecuteDispatchCallbacks) {
	switch req.Decision.Harness {
	case "fiz", "":
		if cb.RunNative != nil {
			cb.RunNative(ctx)
		}
	case "claude":
		runSubprocess(ctx, cb, &claudeharness.Runner{})
	case "codex":
		runSubprocess(ctx, cb, &codexharness.Runner{})
	case "gemini":
		runSubprocess(ctx, cb, &geminiharness.Runner{})
	case "opencode":
		runSubprocess(ctx, cb, &opencodeharness.Runner{})
	case "pi":
		runSubprocess(ctx, cb, &piharness.Runner{})
	case "virtual":
		if cb.RunVirtual != nil {
			cb.RunVirtual(ctx)
		}
	case "script":
		if cb.RunScript != nil {
			cb.RunScript(ctx)
		}
	default:
		if cb.IsHTTPProvider != nil && cb.IsHTTPProvider(req.Decision.Harness) {
			if cb.RunNative != nil {
				cb.RunNative(ctx)
			}
			return
		}
		finalizeDispatch(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      fmt.Sprintf("harness %q dispatch not yet wired in service.Execute", req.Decision.Harness),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        req.Decision.Harness,
				Provider:       req.Decision.Provider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          req.Decision.Model,
			},
		})
	}
}

func runSubprocess(ctx context.Context, cb ExecuteDispatchCallbacks, runner harnesses.Harness) {
	if cb.RunSubprocess != nil {
		cb.RunSubprocess(ctx, runner)
	}
}

func finalizeDispatch(cb ExecuteDispatchCallbacks, final harnesses.FinalData) {
	if cb.Finalize != nil {
		cb.Finalize(final)
	}
}

