func TestSessionLogPathRejectsMissingInputs(t *testing.T) {
	if _, err := SessionLogPath("", "svc-123"); err == nil {
		t.Fatal("SessionLogPath empty dir: got nil error")
	}
	if _, err := SessionLogPath("/logs", ""); err == nil {
