func transcriptRouteDecision(decision RouteDecision) transcript.RouteDecisionSummary {
	out := transcript.RouteDecisionSummary{
		Harness:  decision.Harness,
		Provider: decision.Provider,
		Model:    decision.Model,
		Power:    decision.Power,
	}
	if len(decision.Candidates) == 0 {
		return out
	}
	out.Candidates = make([]transcript.RouteCandidateSummary, len(decision.Candidates))
	for i, candidate := range decision.Candidates {
		out.Candidates[i] = transcript.RouteCandidateSummary{
			Harness:            candidate.Harness,
			Provider:           candidate.Provider,
			Model:              candidate.Model,
			CostUSDPer1kTokens: candidate.CostUSDPer1kTokens,
			CostSource:         candidate.CostSource,
			Components: transcript.RouteCandidateComponentsSummary{
				Power:    candidate.Components.Power,
				SpeedTPS: candidate.Components.SpeedTPS,
			},
		}
	}
	return out
}

